MatAdd._print_MatAdd.code_content:
def _print_MatAdd(self, expr):
    terms = [self.parenthesize(arg, precedence(expr))
         for arg in expr.args]
    l = []
    for t in terms:
        if t.startswith('-'):
            sign = "-"
            t = t[1:]
        else:
            sign = "+"
        l.extend([sign, t])
    sign = l.pop(0)
    if sign == '+':
        sign = ""
    return sign + ' '.join(l)

