def clear_cache(self):
    """clear cache content"""
    for item in self:
        myfunc = item
        while hasattr(myfunc, '__wrapped__'):
            if hasattr(myfunc, 'cache_clear'):
                myfunc.cache_clear()
                break
            else:
                myfunc = myfunc.__wrapped__

