sympy.core.evaluate.evaluate.code_content:
def evaluate(self, x, a=None):
    f = self

    if isinstance(x, list) and a is None:
        (X, a), x = x[0], x[1:]
        f = f.evaluate(X, a)

        if not x:
            return f
        else:
            x = [ (Y.drop(X), a) for (Y, a) in x ]
            return f.evaluate(x)

    ring = f.ring
    i = ring.index(x)
    a = ring.domain.convert(a)

    if ring.ngens == 1:
        result = ring.domain.zero

        for (n,), coeff in f.iterterms():
            result += coeff*a**n

        return result
    else:
        poly = ring.drop(x).zero

        for monom, coeff in f.iterterms():
            n, monom = monom[i], monom[:i] + monom[i+1:]
            coeff = coeff*a**n

            if monom in poly:
                coeff = coeff + poly[monom]

                if coeff:
                    poly[monom] = coeff
                else:
                    del poly[monom]
            else:
                if coeff:
                    poly[monom] = coeff

        return poly

