def shape(self):
    shape = []
    for size, k in zip(self.array.shape, self.key.tuple):
        if isinstance(k, slice):
            shape.append(len(range(*k.indices(size))))
        elif isinstance(k, np.ndarray):
            shape.append(k.size)
    return tuple(shape)

